content:
{
  "sentences": [
    {
      "text": "他不但會說中文，而且寫得也很好。",
      "pinyin": "Tā bùdàn huì shuō zhōngwén, érqiě xiě de yě hěn hǎo.",
      "pinyin_numeric": "ta1 bu4dan4 hui4 shuo1 zhong1wen2, er2qie3 xie3 de0 ye3 hen3 hao3.",
      "translation_en": "He can not only speak Chinese but also write it very well.",
      "translation_ko": "그는 중국어를 말할 뿐만 아니라 글쓰기도 아주 잘합니다."
    },
    {
      "text": "這家餐廳不但東西好吃，而且價錢也很便宜。",
      "pinyin": "Zhè jiā cāntīng bùdàn dōngxi hǎochī, érqiě jiàqián yě hěn piányí.",
      "pinyin_numeric": "zhe4 jia1 can1ting1 bu4dan4 dong1xi0 hao3chi1, er2qie3 jia4qian2 ye3 hen3 pian2yi2.",
      "translation_en": "This restaurant not only has delicious food but also has very cheap prices.",
      "translation_ko": "이 식당은 음식이 맛있을 뿐만 아니라 가격도 아주 저렴합니다."
    },
    {
      "text": "我妹妹不但漂亮，而且也很聰明。",
      "pinyin": "Wǒ mèimei bùdàn piàoliang, érqiě yě hěn cōngmíng.",
      "pinyin_numeric": "wo3 mei4mei0 bu4dan4 piao4liang0, er2qie3 ye3 hen3 cong1ming2.",
      "translation_en": "My younger sister is not only pretty but also very smart.",
      "translation_ko": "제 여동생은 예쁠 뿐만 아니라 아주 똑똑합니다."
    },
    {
      "text": "今天不但天氣很冷，而且還下雨了。",
      "pinyin": "Jīntiān bùdàn tiānqì hěn lěng, érqiě hái xià yǔ le.",
      "pinyin_numeric": "jin1tian1 bu4dan4 tian1qi4 hen3 leng3, er2qie3 hai2 xia4 yu3 le0.",
      "translation_en": "Today is not only very cold but also rainy.",
      "translation_ko": "오늘은 날씨가 추울 뿐만 아니라 비도 내렸습니다."
    },
    {
      "text": "他不但工作認真，而且對同事也很好。",
      "pinyin": "Tā bùdàn gōngzuò rènzhēn, érqiě duì tóngshì yě hěn hǎo.",
      "pinyin_numeric": "ta1 bu4dan4 gong1zuo4 ren4zhen1, er2qie3 dui4 tong2shi4 ye3 hen3 hao3.",
      "translation_en": "He is not only hardworking at work but also very kind to his colleagues.",
      "translation_ko": "그는 일을 열심히 할 뿐만 아니라 동료들에게도 아주 좋습니다."
    },
    {
      "text": "這家店不但東西便宜，而且品質也很好。",
      "pinyin": "Zhè jiā diàn bùdàn dōngxi piányí, érqiě pǐnzhì yě hěn hǎo.",
      "pinyin_numeric": "zhe4 jia1 dian4 bu4dan4 dong1xi0 pian2yi2, er2qie3 pin3zhi4 ye3 hen3 hao3.",
      "translation_en": "This store not only has cheap items but also good quality.",
      "translation_ko": "이 가게는 물건이 저렴할 뿐만 아니라 품질도 좋습니다."
    },
    {
      "text": "我朋友不但喜歡唱歌，而且也很會跳舞。",
      "pinyin": "Wǒ péngyou bùdàn xǐhuān chànggē, érqiě yě hěn huì tiàowǔ.",
      "pinyin_numeric": "wo3 peng2you0 bu4dan4 xi3huan1 chang4ge1, er2qie3 ye3 hen3 hui4 tiao4wu3.",
      "translation_en": "My friend not only likes singing but is also very good at dancing.",
      "translation_ko": "제 친구는 노래 부르기를 좋아할 뿐만 아니라 춤도 아주 잘 춥니다."
    },
    {
      "text": "這本書不但內容有意思，而且也不貴。",
      "pinyin": "Zhè běn shū bùdàn nèiróng yǒu yìsi, érqiě yě bù guì.",
      "pinyin_numeric": "zhe4 ben3 shu1 bu4dan4 nei4rong2 you3 yi4si0, er2qie3 ye3 bu4 gui4.",
      "translation_en": "This book is not only interesting in content but also not expensive.",
      "translation_ko": "이 책은 내용이 재미있을 뿐만 아니라 가격도 비싸지 않습니다."
    },
    {
      "text": "他不但會煮飯，而且煮得也很好吃。",
      "pinyin": "Tā bùdàn huì zhǔ fàn, érqiě zhǔ de yě hěn hǎochī.",
      "pinyin_numeric": "ta1 bu4dan4 hui4 zhu3 fan4, er2qie3 zhu3 de0 ye3 hen3 hao3chi1.",
      "translation_en": "He can not only cook but also cooks very deliciously.",
      "translation_ko": "그는 요리를 할 뿐만 아니라 아주 맛있게 합니다."
    },
    {
      "text": "這家咖啡店不但氣氛好，而且咖啡也很好喝。",
      "pinyin": "Zhè jiā kāfēi diàn bùdàn qìfēn hǎo, érqiě kāfēi yě hěn hǎohē.",
      "pinyin_numeric": "zhe4 jia1 ka1fei1 dian4 bu4dan4 qi4fen1 hao3, er2qie3 ka1fei1 ye3 hen3 hao3he1.",
      "translation_en": "This coffee shop not only has a good atmosphere but also has great coffee.",
      "translation_ko": "이 커피숍은 분위기가 좋을 뿐만 아니라 커피도 아주 맛있습니다."
    }
  ]
}
